#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 5;

int n, y[N], c1[N], c2[N], high1[N], high2[N], low1[N], low2[N];

inline int lowbit(int x)
{
    return x & -x;
}

void add(int x, int c[])
{
    for(; x <= n; x += lowbit(x))
        c[x] += 1;
}

int getsum(int x, const int c[])
{
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}

int main()
{
    cin >> n;
    for(int i = 1; i <= n; i++)
        cin >> y[i];
    for(int i = 1; i <= n; i++)
    {
        int x = y[i];
        if(1 < i && i < n)
            low1[i] = getsum(x - 1, c1), high1[i] = i - 1 - getsum(x, c1);
        add(x, c1);
    }
    for(int i = n; i >= 1; i--)
    {
        int x = y[i];
        if(1 < i && i < n)
            low2[i] = getsum(x - 1, c2), high2[i] = n - i - getsum(x, c2);
        add(x, c2);
    }
    long long ans1 = 0, ans2 = 0;
    for(int i = 1; i <= n; i++)
    {
        ans1 += 1ll * high1[i] * high2[i];
        ans2 += 1ll * low1[i] * low2[i];
    }
    cout << ans1 << ' ' << ans2;
    return 0;
}
